SELECT 
  FROM er.tn_er_data_gap g
 WHERE g.er_id  = #{erId}
   AND g.gap_sn = #{gapSn}
   AND NOW() BETWEEN g.use_bgng_dt AND g.use_end_dt

SELECT COALESCE(MAX(gap_sn), 0) + 1
  FROM er.tn_er_data_gap
 WHERE er_id = #{erId}

mapper.update:
UPDATE er.tn_er_data_gap
   SET use_end_dt       = NOW() - INTERVAL '1 minute',
       last_chg_dt      = NOW(),
       last_chg_user_id = #{userId}
 WHERE er_id  = #{erId}
   AND gap_sn = #{gapSn}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt
